import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "Papa's Bot", the expert printing consultant for Papa's Signs, a digital printing company in Kuruman.
Your goal is to help customers define their printing needs so they can get an accurate quote.
Services include: Large format printing, Vehicle branding, Shopfront signage, Canvas prints, Banners (PVC, Roll-up), Business cards, Flyers, and Chromadek signs.

Guidelines:
1. Be friendly, professional, and concise.
2. Ask clarifying questions if the user's request is vague (e.g., ask for dimensions, indoor vs outdoor use, quantity).
3. Recommend materials based on their needs (e.g., "For outdoor long-term signs, we recommend Chromadek or cast vinyl.").
4. Once you have enough details (Item, Size, Material, Quantity), summarize the request and tell them to click the "Request Quote" button below with this info.
5. Do not give specific prices, as these depend on current material costs. Say "I can help you prepare the details for a quote from our sales team."
`;

let chatSession: Chat | null = null;

export const initializeChat = (): void => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      console.warn("API Key not found in environment variables.");
      return;
    }

    const ai = new GoogleGenAI({ apiKey });

    chatSession = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });
  } catch (error) {
    console.error("Failed to initialize Gemini chat:", error);
  }
};

export const sendMessageToGemini = async (message: string): Promise<string> => {
  if (!chatSession) {
    initializeChat();
    if (!chatSession) {
       return "I'm having trouble connecting to the server right now. Please try again later or contact us directly.";
    }
  }

  try {
    const result: GenerateContentResponse = await chatSession.sendMessage({ message });
    return result.text || "I didn't catch that. Could you rephrase?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I encountered an error processing your request. Please try again.";
  }
};

