import React, { useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Navbar from './components/Navbar';
import Footer from './components/Footer';

// Pages
import Home from './pages/Home';
import AboutPage from './pages/AboutPage';
import ServicesPage from './pages/ServicesPage';
import ServiceCategoryPage from './pages/ServiceCategoryPage';
import GalleryPage from './pages/GalleryPage';
import QuotePage from './pages/QuotePage';
import ContactPage from './pages/ContactPage';
import PrivacyPolicyPage from './pages/PrivacyPolicyPage';
import TermsOfServicePage from './pages/TermsOfServicePage';
import SmartMockupPage from './pages/SmartMockupPage';

// Scroll to top on route change component
const ScrollToTop = () => {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

const App: React.FC = () => {
  useEffect(() => {
    // Basic connectivity check for Gemini
    if (!process.env.API_KEY) {
      console.warn("Gemini API Key is missing. The Chat Assistant will not function correctly.");
    }
  }, []);

  return (
    <Router>
      <div className="min-h-screen flex flex-col font-sans">
        <Navbar />
        <ScrollToTop />
        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/about" element={<AboutPage />} />
            <Route path="/services" element={<ServicesPage />} />
            <Route path="/services/:categoryId" element={<ServiceCategoryPage />} />
            <Route path="/gallery" element={<GalleryPage />} />
            <Route path="/mockup" element={<SmartMockupPage />} />
            <Route path="/quote" element={<QuotePage />} />
            <Route path="/contact" element={<ContactPage />} />
            <Route path="/privacy-policy" element={<PrivacyPolicyPage />} />
            <Route path="/terms-of-service" element={<TermsOfServicePage />} />
            {/* Fallback to Home */}
            <Route path="*" element={<Home />} />
          </Routes>
        </main>
        <Footer />
      </div>
    </Router>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Upload, Image as ImageIcon, Download, Move, ZoomIn, RotateCw, Monitor, Shirt, Coffee, Truck, Layout } from 'lucide-react';
import { Link } from 'react-router-dom';

interface MockupTemplate {
  id: string;
  name: string;
  category: string;
  icon: React.ReactNode;
  image: string;
  // Overlay configuration defining where the user logo goes
  overlay: {
    top: string;
    left: string;
    width: string;
    height: string;
    perspective?: string;
    rotateX?: string;
    rotateY?: string;
    rotateZ?: string;
    blendMode: 'normal' | 'multiply' | 'screen' | 'overlay' | 'darken';
    opacity: number;
  };
}

const SmartMockupPage: React.FC = () => {
  const [selectedTemplate, setSelectedTemplate] = useState<string>('tshirt-white');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);

  // Transformation Controls
  const [scale, setScale] = useState(1);
  const [rotation, setRotation] = useState(0);
  const [offsetX, setOffsetX] = useState(0);
  const [offsetY, setOffsetY] = useState(0);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const templates: MockupTemplate[] = [
    {
      id: 'tshirt-white',
      name: 'White T-Shirt',
      category: 'Apparel',
      icon: <Shirt className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1581655353564-df123a1eb820?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '25%',
        left: '28%',
        width: '44%',
        height: '55%',
        blendMode: 'multiply',
        opacity: 0.9,
      }
    },
    {
      id: 'billboard',
      name: 'Highway Billboard',
      category: 'Outdoor',
      icon: <Layout className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '12%',
        left: '14%',
        width: '72%',
        height: '53%',
        blendMode: 'normal',
        opacity: 0.95,
      }
    },
    {
      id: 'van',
      name: 'Delivery Van',
      category: 'Vehicle',
      icon: <Truck className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1517048676732-d65bc937f952?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '25%',
        left: '15%',
        width: '55%',
        height: '35%',
        blendMode: 'multiply',
        opacity: 0.9,
        rotateZ: '2deg' // Slight rotation for the van angle
      }
    },
    {
      id: 'mug',
      name: 'Coffee Mug',
      category: 'Gifts',
      icon: <Coffee className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1514228742587-6b1558fcca3d?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '35%',
        left: '30%',
        width: '40%',
        height: '40%',
        blendMode: 'multiply',
        opacity: 0.85,
      }
    },
    {
      id: 'screen',
      name: 'Digital Display',
      category: 'Digital',
      icon: <Monitor className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1526666923127-b2970f64b422?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '10%',
        left: '10%',
        width: '80%',
        height: '65%',
        blendMode: 'screen',
        opacity: 0.95,
      }
    }
  ];

  const currentTemplate = templates.find(t => t.id === selectedTemplate) || templates[0];

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setUploadedImage(e.target?.result as string);
        // Reset transforms on new image
        setScale(1);
        setRotation(0);
        setOffsetX(0);
        setOffsetY(0);
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="pt-20 bg-gray-50 min-h-screen animate-fade-in">

      {/* Hero Header */}
      <div className="bg-brand-dark text-white py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-3xl md:text-5xl font-black mb-4">Smart Mockup Studio</h1>
          <p className="text-gray-400 max-w-2xl mx-auto text-lg">
            Visualize your brand in the real world. Select a product, upload your design, and see the magic happen instantly before you order.
          </p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* LEFT COLUMN: Controls & Templates */}
          <div className="lg:w-1/3 space-y-8">

            {/* Template Selector */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                <Layout className="w-5 h-5 text-brand-cyan" /> Select Product
              </h3>
              <div className="grid grid-cols-2 gap-3">
                {templates.map((t) => (
                  <button
                    key={t.id}
                    onClick={() => setSelectedTemplate(t.id)}
                    className={`p-3 rounded-xl border-2 transition-all flex flex-col items-center gap-2 text-sm font-medium ${
                      selectedTemplate === t.id
                        ? 'border-brand-cyan bg-brand-cyan/5 text-brand-cyan'
                        : 'border-gray-100 hover:border-gray-200 text-gray-600'
                    }`}
                  >
                    <div className={selectedTemplate === t.id ? 'text-brand-cyan' : 'text-gray-400'}>
                      {t.icon}
                    </div>
                    {t.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Upload & Edit Controls */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                <ImageIcon className="w-5 h-5 text-brand-magenta" /> Design
              </h3>

              <div className="mb-6">
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleImageUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
                <button 
                  onClick={triggerUpload}
                  className="w-full py-4 border-2 border-dashed border-gray-300 rounded-xl flex flex-col items-center justify-center text-gray-500 hover:border-brand-cyan hover:text-brand-cyan hover:bg-brand-cyan/5 transition-all"
                >
                  <Upload className="w-6 h-6 mb-2" />
                  <span className="font-bold text-sm">Upload Your Logo/Design</span>
                  <span className="text-xs mt-1 text-gray-400">PNG, JPG recommended</span>
                </button>
              </div>

              {uploadedImage && (
                <div className="space-y-4 animate-fade-in">
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center justify-between">
                      <span className="flex items-center gap-1"><ZoomIn className="w-3 h-3" /> Size</span>
                      <span>{Math.round(scale * 100)}%</span>
                    </label>
                    <input 
                      type="range" 
                      min="0.1" 
                      max="2" 
                      step="0.05" 
                      value={scale} 
                      onChange={(e) => setScale(parseFloat(e.target.value))}
                      className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-cyan"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center justify-between">
                      <span className="flex items-center gap-1"><RotateCw className="w-3 h-3" /> Rotate</span>
                      <span>{rotation}°</span>
                    </label>
                    <input 
                      type="range" 
                      min="-180" 
                      max="180" 
                      value={rotation} 
                      onChange={(e) => setRotation(parseInt(e.target.value))}
                      className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-magenta"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center gap-1">
                      <Move className="w-3 h-3" /> Position Offset
                    </label>
                    <div className="grid grid-cols-2 gap-2">
                       <button onClick={() => setOffsetX(0)} className="text-xs bg-gray-100 p-2 rounded hover:bg-gray-200">Reset X</button>
                       <button onClick={() => setOffsetY(0)} className="text-xs bg-gray-100 p-2 rounded hover:bg-gray-200">Reset Y</button>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* RIGHT COLUMN: Preview Canvas */}
          <div className="lg:w-2/3">
            <div className="bg-white p-2 rounded-[2rem] shadow-2xl border border-gray-100 relative overflow-hidden group">
              <div className="relative w-full aspect-[4/3] bg-gray-100 rounded-[1.5rem] overflow-hidden">

                {/* Product Base Image */}
                <img 
                  src={currentTemplate.image} 
                  alt={currentTemplate.name} 
                  className="w-full h-full object-cover relative z-10 pointer-events-none"
                />

                {/* Overlay Area Indicator (Optional - visible on hover or empty) */}
                {!uploadedImage && (
                  <div 
                    className="absolute z-20 border-2 border-dashed border-brand-cyan/50 bg-brand-cyan/10 flex items-center justify-center text-brand-cyan font-bold text-sm pointer-events-none"
                    style={{
                      top: currentTemplate.overlay.top,
                      left: currentTemplate.overlay.left,
                      width: currentTemplate.overlay.width,
                      height: currentTemplate.overlay.height,
                    }}
                  >
                    Your Design Here
                  </div>
                )}

                {/* User Design Layer */}
                {uploadedImage && (
                  <div 
                    className="absolute z-20 overflow-hidden flex items-center justify-center"
                    style={{
                      top: currentTemplate.overlay.top,
                      left: currentTemplate.overlay.left,
                      width: currentTemplate.overlay.width,
                      height: currentTemplate.overlay.height,
                      mixBlendMode: currentTemplate.overlay.blendMode as any,
                      opacity: currentTemplate.overlay.opacity,
                      transform: `
                        perspective(1000px) 
                        rotateX(${currentTemplate.overlay.rotateX || '0deg'}) 
                        rotateY(${currentTemplate.overlay.rotateY || '0deg'}) 
                        rotateZ(${currentTemplate.overlay.rotateZ || '0deg'})
                      `
                    }}
                  >
                    <img 
                      src={uploadedImage} 
                      alt="User Upload" 
                      className="max-w-none origin-center"
                      style={{
                        transform: `
                          translate(${offsetX}px, ${offsetY}px) 
                          rotate(${rotation}deg) 
                          scale(${scale})
