                      }}
                    />
                  </div>
                )}

                {/* Lighting/Texture Overlay (Optional top layer for realism) */}
                <div className="absolute inset-0 z-30 pointer-events-none bg-gradient-to-tr from-black/5 to-transparent mix-blend-multiply"></div>
                <div className="absolute inset-0 z-30 pointer-events-none bg-gradient-to-bl from-white/10 to-transparent mix-blend-soft-light"></div>
              </div>

              {/* Action Bar */}
              <div className="absolute bottom-6 right-6 z-40 flex gap-2">
                <button 
                  onClick={() => {
                     setUploadedImage(null);
                     setScale(1);
                     setRotation(0);
