// 3D Model Component
const MockupMesh: React.FC<{ templateId: string; uploadedImage: string | null }> = ({ templateId, uploadedImage }) => {
  const texture = useTexture(uploadedImage || TRANSPARENT_PIXEL);

  // Ensure texture encoding is correct for 3D lighting
  texture.colorSpace = THREE.SRGBColorSpace;

  switch (templateId) {
    case 'mug':
      return (
        <mesh castShadow receiveShadow position={[0, 0.5, 0]}>
          <cylinderGeometry args={[0.8, 0.8, 2, 64]} />
          <meshStandardMaterial color="white" roughness={0.2} metalness={0.1} />
          {uploadedImage && (
            <Decal 
              position={[0, 0, 0.8]} 
              rotation={[0, 0, 0]} 
              scale={[1.2, 1.2, 1]} 
              map={texture} 
            />
          )}
          {/* Handle */}
          <mesh position={[0.9, 0, 0]} rotation={[0, 0, Math.PI / 2]}>
             <torusGeometry args={[0.5, 0.15, 16, 32, Math.PI]} />
             <meshStandardMaterial color="white" />
          </mesh>
        </mesh>
      );

    case 'billboard':
      return (
        <group position={[0, 1, 0]}>
          {/* Post */}
          <mesh position={[0, -2, 0]} castShadow receiveShadow>
             <cylinderGeometry args={[0.2, 0.2, 4]} />
             <meshStandardMaterial color="#333" />
          </mesh>
          {/* Board */}
          <mesh castShadow receiveShadow>
            <boxGeometry args={[4, 2.25, 0.2]} />
            <meshStandardMaterial color="#f5f5f5" />
            {uploadedImage && (
              <Decal position={[0, 0, 0.11]} rotation={[0, 0, 0]} scale={[3.8, 2.1, 1]} map={texture} />
            )}
          </mesh>
        </group>
      );

    case 'van':
      return (
        <group position={[0, 0.5, 0]}>
           {/* Body */}
           <mesh position={[0, 0.5, 0]} castShadow receiveShadow>
              <boxGeometry args={[4, 2, 1.8]} />
              <meshStandardMaterial color="white" roughness={0.2} />
              {uploadedImage && (
                <Decal position={[0, 0, 0.91]} rotation={[0, 0, 0]} scale={[3, 1.5, 1]} map={texture} />
              )}
           </mesh>
           {/* Wheels */}
           <mesh position={[-1.2, -0.5, 0.9]} rotation={[Math.PI/2, 0, 0]}>
              <cylinderGeometry args={[0.4, 0.4, 0.2, 32]} />
              <meshStandardMaterial color="#333" />
           </mesh>
           <mesh position={[1.2, -0.5, 0.9]} rotation={[Math.PI/2, 0, 0]}>
              <cylinderGeometry args={[0.4, 0.4, 0.2, 32]} />
              <meshStandardMaterial color="#333" />
           </mesh>
           <mesh position={[-1.2, -0.5, -0.9]} rotation={[Math.PI/2, 0, 0]}>
              <cylinderGeometry args={[0.4, 0.4, 0.2, 32]} />
              <meshStandardMaterial color="#333" />
           </mesh>
           <mesh position={[1.2, -0.5, -0.9]} rotation={[Math.PI/2, 0, 0]}>
              <cylinderGeometry args={[0.4, 0.4, 0.2, 32]} />
              <meshStandardMaterial color="#333" />
           </mesh>
        </group>
      );

    case 'screen':
      return (
        <group position={[0, 1, 0]}>
          <mesh castShadow receiveShadow>
            <boxGeometry args={[4, 2.5, 0.1]} />
            <meshStandardMaterial color="#111" roughness={0.2} metalness={0.8} />
            {uploadedImage && (
              <Decal position={[0, 0, 0.06]} rotation={[0, 0, 0]} scale={[3.9, 2.4, 1]} map={texture} />
            )}
          </mesh>
           {/* Stand */}
           <mesh position={[0, -1.5, 0]}>
              <cylinderGeometry args={[0.1, 0.4, 1]} />
              <meshStandardMaterial color="#111" />
           </mesh>
           <mesh position={[0, -2, 0]}>
              <cylinderGeometry args={[0.8, 0.8, 0.1]} />
              <meshStandardMaterial color="#111" />
           </mesh>
        </group>
      );

    default: // tshirt or generic
       return (
        <group>
           <mesh castShadow receiveShadow rotation={[0, 0, 0]} position={[0, 0, 0]}>
            <boxGeometry args={[2.5, 3, 0.1]} />
            <meshStandardMaterial color="white" />
            {uploadedImage && (
              <Decal position={[0, 0, 0.06]} rotation={[0, 0, 0]} scale={[1.8, 1.8, 1]} map={texture} />
            )}
          </mesh>
          {/* Neckline approximation */}
           <mesh position={[0, 1.4, 0]} castShadow>
             <cylinderGeometry args={[0.4, 0.4, 0.2, 32]} />
             <meshStandardMaterial color="#eee" />
           </mesh>
        </group>
      );
  }
};

