import React, { useState, useRef, Suspense } from 'react';
import { Upload, Image as ImageIcon, Download, Move, ZoomIn, RotateCw, Monitor, Shirt, Coffee, Truck, Layout, Box as BoxIcon, Rotate3D } from 'lucide-react';
