        width: '55%',
        height: '35%',
        blendMode: 'multiply',
        opacity: 0.9,
        rotateZ: '2deg'
      }
    },
    {
      id: 'mug',
      name: 'Coffee Mug',
      category: 'Gifts',
      icon: <Coffee className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1514228742587-6b1558fcca3d?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '35%',
        left: '30%',
        width: '40%',
        height: '40%',
        blendMode: 'multiply',
        opacity: 0.85,
      }
    },
    {
      id: 'screen',
      name: 'Digital Display',
      category: 'Digital',
      icon: <Monitor className="w-5 h-5" />,
      image: 'https://images.unsplash.com/photo-1526666923127-b2970f64b422?auto=format&fit=crop&q=80&w=1000',
      overlay: {
        top: '10%',
        left: '10%',
        width: '80%',
        height: '65%',
        blendMode: 'screen',
        opacity: 0.95,
      }
    }
  ];

  const currentTemplate = templates.find(t => t.id === selectedTemplate) || templates[0];

  const handleImageUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setUploadedImage(e.target?.result as string);
        // Reset transforms on new image
        setScale(1);
        setRotation(0);
        setOffsetX(0);
        setOffsetY(0);
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="pt-20 bg-gray-50 min-h-screen animate-fade-in">

      {/* Hero Header */}
      <div className="bg-brand-dark text-white py-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-3xl md:text-5xl font-black mb-4">Smart Mockup Studio</h1>
          <p className="text-gray-400 max-w-2xl mx-auto text-lg">
            Visualize your brand in the real world. Switch between standard proofs and interactive 3D models instantly.
          </p>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="flex flex-col lg:flex-row gap-8">

          {/* LEFT COLUMN: Controls & Templates */}
          <div className="lg:w-1/3 space-y-8">

            {/* Template Selector */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                <Layout className="w-5 h-5 text-brand-cyan" /> Select Product
              </h3>
              <div className="grid grid-cols-2 gap-3">
                {templates.map((t) => (
                  <button
                    key={t.id}
                    onClick={() => setSelectedTemplate(t.id)}
                    className={`p-3 rounded-xl border-2 transition-all flex flex-col items-center gap-2 text-sm font-medium ${
                      selectedTemplate === t.id
                        ? 'border-brand-cyan bg-brand-cyan/5 text-brand-cyan'
                        : 'border-gray-100 hover:border-gray-200 text-gray-600'
                    }`}
                  >
                    <div className={selectedTemplate === t.id ? 'text-brand-cyan' : 'text-gray-400'}>
                      {t.icon}
                    </div>
                    {t.name}
                  </button>
                ))}
              </div>
            </div>

            {/* Upload & Edit Controls */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                <ImageIcon className="w-5 h-5 text-brand-magenta" /> Design
              </h3>

              <div className="mb-6">
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleImageUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
                <button 
                  onClick={triggerUpload}
                  className="w-full py-4 border-2 border-dashed border-gray-300 rounded-xl flex flex-col items-center justify-center text-gray-500 hover:border-brand-cyan hover:text-brand-cyan hover:bg-brand-cyan/5 transition-all"
                >
                  <Upload className="w-6 h-6 mb-2" />
                  <span className="font-bold text-sm">Upload Your Logo/Design</span>
                  <span className="text-xs mt-1 text-gray-400">PNG, JPG recommended</span>
                </button>
              </div>

              {uploadedImage && !is3DMode && (
                <div className="space-y-4 animate-fade-in">
                  <div className="p-3 bg-blue-50 text-blue-800 rounded-lg text-xs font-semibold mb-2">
                    2D Positioning Controls
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center justify-between">
                      <span className="flex items-center gap-1"><ZoomIn className="w-3 h-3" /> Size</span>
                      <span>{Math.round(scale * 100)}%</span>
                    </label>
                    <input 
                      type="range" 
                      min="0.1" 
                      max="2" 
                      step="0.05" 
                      value={scale} 
                      onChange={(e) => setScale(parseFloat(e.target.value))}
                      className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-cyan"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center justify-between">
                      <span className="flex items-center gap-1"><RotateCw className="w-3 h-3" /> Rotate</span>
                      <span>{rotation}°</span>
                    </label>
                    <input 
                      type="range" 
                      min="-180" 
                      max="180" 
                      value={rotation} 
                      onChange={(e) => setRotation(parseInt(e.target.value))}
                      className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-brand-magenta"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-xs font-bold text-gray-500 uppercase flex items-center gap-1">
                      <Move className="w-3 h-3" /> Position Offset
                    </label>
                    <div className="grid grid-cols-2 gap-2">
                       <button onClick={() => setOffsetX(0)} className="text-xs bg-gray-100 p-2 rounded hover:bg-gray-200">Reset X</button>
                       <button onClick={() => setOffsetY(0)} className="text-xs bg-gray-100 p-2 rounded hover:bg-gray-200">Reset Y</button>
                    </div>
                  </div>
                </div>
              )}
              {is3DMode && (
                <div className="p-4 bg-brand-yellow/10 text-brand-black rounded-xl text-sm leading-relaxed">
                   <strong className="block mb-1">3D Controls Enabled</strong>
                   Click and drag on the preview to rotate the model. Scroll to zoom in/out.
                </div>
              )}
            </div>
          </div>

          {/* RIGHT COLUMN: Preview Canvas */}
          <div className="lg:w-2/3">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-bold text-xl text-brand-black">Preview</h3>

              {/* Toggle Switch */}
              <div className="bg-white p-1 rounded-xl shadow-sm border border-gray-100 flex">
                <button
                  onClick={() => setIs3DMode(false)}
                  className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${!is3DMode ? 'bg-brand-black text-white shadow-md' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  <ImageIcon className="w-4 h-4" /> 2D Proof
                </button>
                <button
                  onClick={() => setIs3DMode(true)}
                  className={`px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 transition-all ${is3DMode ? 'bg-brand-cyan text-white shadow-md' : 'text-gray-500 hover:bg-gray-100'}`}
                >
                  <Rotate3D className="w-4 h-4" /> 3D Interactive
                </button>
              </div>
            </div>

            <div className="bg-white p-2 rounded-[2rem] shadow-2xl border border-gray-100 relative overflow-hidden group">
              <div className="relative w-full aspect-[4/3] bg-gray-100 rounded-[1.5rem] overflow-hidden">

                {!is3DMode ? (
                  // 2D View
                  <>
                    <img 
                      src={currentTemplate.image} 
                      alt={currentTemplate.name} 
                      className="w-full h-full object-cover relative z-10 pointer-events-none"
                    />

                    {!uploadedImage && (
                      <div 
                        className="absolute z-20 border-2 border-dashed border-brand-cyan/50 bg-brand-cyan/10 flex items-center justify-center text-brand-cyan font-bold text-sm pointer-events-none"
                        style={{
                          top: currentTemplate.overlay.top,
                          left: currentTemplate.overlay.left,
                          width: currentTemplate.overlay.width,
                          height: currentTemplate.overlay.height,
                        }}
                      >
                        Your Design Here
                      </div>
                    )}

                    {uploadedImage && (
                      <div 
                        className="absolute z-20 overflow-hidden flex items-center justify-center"
                        style={{
                          top: currentTemplate.overlay.top,
                          left: currentTemplate.overlay.left,
                          width: currentTemplate.overlay.width,
                          height: currentTemplate.overlay.height,
                          mixBlendMode: currentTemplate.overlay.blendMode as any,
                          opacity: currentTemplate.overlay.opacity,
                          transform: `
                            perspective(1000px) 
                            rotateX(${currentTemplate.overlay.rotateX || '0deg'}) 
                            rotateY(${currentTemplate.overlay.rotateY || '0deg'}) 
                            rotateZ(${currentTemplate.overlay.rotateZ || '0deg'})
                          `
                        }}
                      >
                        <img 
                          src={uploadedImage} 
                          alt="User Upload" 
                          className="max-w-none origin-center"
                          style={{
                            transform: `
                              translate(${offsetX}px, ${offsetY}px) 
                              rotate(${rotation}deg) 
                              scale(${scale})
                            `
                          }}
                        />
                      </div>
                    )}

                    <div className="absolute inset-0 z-30 pointer-events-none bg-gradient-to-tr from-black/5 to-transparent mix-blend-multiply"></div>
                  </>
                ) : (
                  // 3D View
                  <div className="w-full h-full bg-gradient-to-br from-gray-200 to-gray-300">
                    <Suspense fallback={
                      <div className="w-full h-full flex items-center justify-center text-gray-500 font-bold gap-2">
                         <div className="w-6 h-6 border-2 border-brand-cyan border-t-transparent rounded-full animate-spin"></div>
                         Loading Model...
                      </div>
                    }>
                      <Canvas shadows dpr={[1, 2]} camera={{ position: [0, 0, 5], fov: 45 }}>
                        <Stage environment="city" intensity={0.5}>
                          <MockupMesh templateId={selectedTemplate} uploadedImage={uploadedImage} />
                        </Stage>
                        <OrbitControls autoRotate={false} />
                      </Canvas>
                    </Suspense>
                    <div className="absolute bottom-4 left-4 bg-white/80 backdrop-blur px-3 py-1 rounded-lg text-xs font-bold text-gray-600 shadow-sm pointer-events-none">
                       Use mouse to rotate & scroll to zoom
                    </div>
                  </div>
                )}
              </div>

              {/* Action Bar */}
              <div className="absolute bottom-6 right-6 z-40 flex gap-2">
                <button 
                  onClick={() => {
                     setUploadedImage(null);
                     setScale(1);
                     setRotation(0);
                  }}
                  className="bg-white text-gray-700 px-4 py-2 rounded-full font-bold text-sm shadow-lg hover:bg-gray-50 flex items-center gap-2"
                >
                  Clear
                </button>
                <Link
                   to="/quote" 
                   state={{ initialMessage: `Quote for ${currentTemplate.name} with custom design` }}
                   className="bg-brand-black text-white px-6 py-2 rounded-full font-bold text-sm shadow-lg hover:bg-brand-cyan transition-colors flex items-center gap-2"
                >
                  Get Quote for this Item
                </Link>
              </div>
            </div>

            <div className="mt-8 bg-brand-yellow/10 p-6 rounded-2xl border border-brand-yellow/20 flex items-start gap-4">
              <div className="bg-brand-yellow/20 p-2 rounded-lg">
                <Download className="w-5 h-5 text-brand-dark" />
              </div>
              <div>
                <h4 className="font-bold text-brand-black text-sm uppercase tracking-wide">Pro Tip</h4>
                <p className="text-gray-700 text-sm mt-1">
                  Like what you see? You can take a screenshot of this mockup to send to our design team, or simply click "Get Quote" to start the conversation with Papa's Bot.
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default SmartMockupPage;
